**Future growth/decay** — Apply multipliers in food update stage:

```rust
fn update_food_growth(&mut self) {
    let cells = self.food.cells_mut();
    for (idx, cell) in cells.iter_mut().enumerate() {
        let profile = &self.food_profiles[idx];
        let growth = self.config.food_growth_rate * profile.growth_multiplier;
        let decay = self.config.food_decay_rate * profile.decay_multiplier;
        *cell = (*cell + growth - decay).clamp(0.0, profile.capacity);
    }
}
